import{app}from"./firebase.min.js";import{getFirestore,doc,setDoc,updateDoc,getDoc,collection,addDoc,query,orderBy,limit,getDocs,serverTimestamp,deleteDoc,runTransaction}from"https://www.gstatic.com/firebasejs/12.1.0/firebase-firestore.js";const db=getFirestore(app);let currentChatDocId=null;export function getCurrentChatDocId(){return currentChatDocId}export function setCurrentChatDocId(t){currentChatDocId=t||null}export function resetCurrentChatDoc(){currentChatDocId=null}export async function saveChatToHistory(t,e,r,s=!1,a={}){try{if(!t)return null;const{mode:o="chat",metadata:c={},chatId:n=null}=a,i=collection(db,"history",t,"chats"),d=(e||"").trim(),l=d.length>0?d:"detect"===o?"AI Detection":"humanize"===o?"Humanizer":"Conversation",u=l.length>40?l.substring(0,40)+"...":l,h=Date.now(),m={sender:"user",text:e||"",createdAt:h,mode:o,metadata:c},g={sender:"ai",text:r||"",createdAt:h,mode:o,metadata:c};if(s||!n){return(await addDoc(i,{title:u,messages:[m,g],createdAt:serverTimestamp(),updatedAt:serverTimestamp(),lastMode:o})).id}const y=doc(db,"history",t,"chats",n);return await runTransaction(db,async t=>{const e=await t.get(y);if(!e.exists())return t.set(y,{title:u,messages:[m,g],createdAt:serverTimestamp(),updatedAt:serverTimestamp(),lastMode:o}),n;const r=e.data(),s=Array.isArray(r.messages)?r.messages:[];return t.update(y,{messages:[...s,m,g],updatedAt:serverTimestamp(),lastMode:o}),n})}catch(t){return console.error("🔥 Error saving chat:",t),null}}export async function getLatestChat(t){try{if(!t)return null;const e=collection(db,"history",t,"chats"),r=query(e,orderBy("createdAt","desc"),limit(1)),s=await getDocs(r);if(!s.empty){const t=s.docs[0];return currentChatDocId=t.id,{chatId:t.id,messages:t.data().messages||[]}}return currentChatDocId=null,null}catch(t){return console.error("🔥 Error retrieving latest chat:",t),currentChatDocId=null,null}}export async function saveFullChatSession(t,e){if(t&&e&&0!==e.length)try{const r=e.find(t=>"user"===t.sender)?.text||"Conversation",s=r.length>30?r.slice(0,30)+"...":r,a=doc(collection(db,"history",t,"sessions"));await setDoc(a,{title:s,messages:e,createdAt:serverTimestamp()}),console.log("✅ Chat session saved:",s)}catch(t){console.error("❌ Failed to save full chat session:",t)}}export async function getAllChats(t){try{if(!t)return console.warn("⚠️ No userId provided to getAllChats()"),[];const e=collection(db,"history",t,"chats"),r=query(e,orderBy("createdAt","desc")),s=await getDocs(r);return s.docs.map(t=>({id:t.id,...t.data()}))}catch(t){return console.error("🔥 Error fetching chats:",t),[]}}export async function getChatById(t,e){if(!t||!e)return console.error("❌ Missing userUID or chatId"),null;try{const r=doc(db,"history",t,"chats",e),s=await getDoc(r);if(!s.exists())return console.warn("⚠️ No such chat:",e),null;const a=s.data(),o=(a.messages||[]).map(t=>({role:"user"===t.sender?"user":"ai",content:t.text||"",mode:t.mode||"chat",metadata:t.metadata||{},createdAt:"number"==typeof t.createdAt?t.createdAt:t.createdAt?.toMillis?t.createdAt.toMillis():null}));return{id:e,...a,messages:o}}catch(t){return console.error("🔥 Error fetching chat by ID:",t),null}}export async function deleteChatHistory(t,e){if(t&&e)try{const r=doc(db,"history",t,"chats",e);await deleteDoc(r),console.log("🗑 Chat deleted:",e)}catch(t){console.error("❌ Failed to delete chat:",t)}}